import React from "react";
// Якщо використовуєте іконки, наприклад react-icons
import { HiSearch, HiBell, HiCalendar } from "react-icons/hi";

const Header = () => {
  return (
    <header className="header-container">
      {/* Логотип / Назва */}
      <div className="logo">
        <span className="logo-red">Dash</span>board
      </div>

      {/* Пошуковий рядок */}
      <div className="search-wrapper">
        <input
          type="text"
          placeholder="Search your task here..."
          className="search-input"
        />
        <button className="search-btn">
          <HiSearch />
        </button>
      </div>

      {/* Права частина: Іконки та Дата */}
      <div className="header-right">
        <button className="icon-btn red-bg">
          <HiBell />
        </button>
        <button className="icon-btn red-bg">
          <HiCalendar />
        </button>

        <div className="date-display">
          <span className="day">Tuesday</span>
          <span className="date">20/06/2023</span>
        </div>
      </div>
    </header>
  );
};

export default Header;
